import{_ as a,o as i,c as n,aj as e}from"./chunks/framework.DpVzuYkC.js";const k=JSON.parse('{"title":"UnifiedPush 配置指南","description":"","frontmatter":{},"headers":[],"relativePath":"ntfy/unifiedpush.md","filePath":"ntfy/unifiedpush.md"}'),l={name:"ntfy/unifiedpush.md"};function p(t,s,h,r,d,c){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="unifiedpush-配置指南" tabindex="-1">UnifiedPush 配置指南 <a class="header-anchor" href="#unifiedpush-配置指南" aria-label="Permalink to “UnifiedPush 配置指南”">​</a></h1><h2 id="什么是-unifiedpush" tabindex="-1">什么是 UnifiedPush？ <a class="header-anchor" href="#什么是-unifiedpush" aria-label="Permalink to “什么是 UnifiedPush？”">​</a></h2><p><a href="https://unifiedpush.org" target="_blank" rel="noreferrer">UnifiedPush</a> 是一个开源的推送通知标准，允许用户在不依赖 Google 服务的情况下接收推送通知。ntfy 可以作为 UnifiedPush 分发商，将消息转发给支持 UnifiedPush 的应用。</p><h2 id="私有实例配置" tabindex="-1">私有实例配置 <a class="header-anchor" href="#私有实例配置" aria-label="Permalink to “私有实例配置”">​</a></h2><p>在私有实例中使用 UnifiedPush，需要解决一个关键问题：<strong>应用服务器（如 Matrix/Synapse、Fediverse 服务器）需要能够向主题发送消息，但它们无法持有用户凭证</strong>。</p><p>解决方案是通过 ACL 配置<strong>匿名读写访问权限</strong>。</p><h3 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to “配置步骤”">​</a></h3><h4 id="_1-创建-env-文件" tabindex="-1">1. 创建 .env 文件 <a class="header-anchor" href="#_1-创建-env-文件" aria-label="Permalink to “1. 创建 .env 文件”">​</a></h4><div class="language-env"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>#=============== 基础配置 ===============</span></span>
<span class="line"><span>NTFY_BASE_URL=http://ntfy.example.com</span></span>
<span class="line"><span>NTFY_LISTEN_HTTP=:80</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#=============== 认证配置 ===============</span></span>
<span class="line"><span>NTFY_AUTH_FILE=/var/lib/ntfy/auth.db</span></span>
<span class="line"><span>NTFY_AUTH_DEFAULT_ACCESS=deny-all</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 用户配置 (可选，根据需要添加)</span></span>
<span class="line"><span># 格式: username:password_hash:role</span></span>
<span class="line"><span># 密码哈希可使用 docker exec -it ntfy ntfy user hash 命令生成</span></span>
<span class="line"><span>NTFY_AUTH_USERS=phil:$2a$10$YLiO8U21sX1uhZamTLJXHuxgVC0Z/GKISibrKCLohPgtG7yIxSk4C:admin</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#=============== UnifiedPush 匿名访问权限 ===============</span></span>
<span class="line"><span># UnifiedPush 既需要发送消息(write)，也需要接收消息(read)</span></span>
<span class="line"><span># 方式一：通配符 (匹配所有 up* 开头的主题)</span></span>
<span class="line"><span>NTFY_AUTH_ACCESS=*:up*:read-write</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 方式二：精确主题 (更安全，只允许特定主题)</span></span>
<span class="line"><span># NTFY_AUTH_ACCESS=*:up随机ID:read-write</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#=============== 缓存配置 ===============</span></span>
<span class="line"><span>NTFY_CACHE_FILE=/var/lib/ntfy/cache.db</span></span>
<span class="line"><span>NTFY_CACHE_DURATION=12h</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#=============== 附件配置 ===============</span></span>
<span class="line"><span>NTFY_ATTACHMENT_CACHE_DIR=/var/lib/ntfy/attachments</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#=============== 反向代理配置 ===============</span></span>
<span class="line"><span>NTFY_BEHIND_PROXY=true</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#=============== 其他配置 ===============</span></span>
<span class="line"><span>NTFY_ENABLE_LOGIN=true</span></span></code></pre></div><h4 id="_2-创建-docker-compose-yml" tabindex="-1">2. 创建 docker-compose.yml <a class="header-anchor" href="#_2-创建-docker-compose-yml" aria-label="Permalink to “2. 创建 docker-compose.yml”">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  ntfy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">binwiederhier/ntfy</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    container_name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ntfy</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    restart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">unless-stopped</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    env_file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.env</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    volumes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">./data:/var/lib/ntfy</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    ports</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">80:80</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">serve</span></span></code></pre></div><h4 id="_3-启动服务" tabindex="-1">3. 启动服务 <a class="header-anchor" href="#_3-启动服务" aria-label="Permalink to “3. 启动服务”">​</a></h4><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><h3 id="配置说明" tabindex="-1">配置说明 <a class="header-anchor" href="#配置说明" aria-label="Permalink to “配置说明”">​</a></h3><table tabindex="0"><thead><tr><th>环境变量</th><th>说明</th></tr></thead><tbody><tr><td><code>NTFY_AUTH_FILE</code></td><td>认证数据库文件路径</td></tr><tr><td><code>NTFY_AUTH_DEFAULT_ACCESS</code></td><td>默认访问权限，<code>deny-all</code> 表示默认拒绝所有访问</td></tr><tr><td><code>NTFY_AUTH_USERS</code></td><td>用户列表，格式：<code>username:password_hash:role</code></td></tr><tr><td><code>NTFY_AUTH_ACCESS</code></td><td>访问控制列表，格式：<code>username:topic:permission</code></td></tr></tbody></table><h3 id="acl-格式说明" tabindex="-1">ACL 格式说明 <a class="header-anchor" href="#acl-格式说明" aria-label="Permalink to “ACL 格式说明”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>username:topic:permission</span></span></code></pre></div><ul><li><strong>username</strong>: 用户名或 <code>*</code> (表示匿名用户)</li><li><strong>topic</strong>: 主题名，支持通配符 <code>*</code></li><li><strong>permission</strong>: 权限类型 <ul><li><code>read-write</code> / <code>rw</code>: 读和写</li><li><code>read-only</code> / <code>ro</code> / <code>read</code>: 只读</li><li><code>write-only</code> / <code>wo</code> / <code>write</code>: 只写</li><li><code>deny</code> / <code>none</code>: 拒绝</li></ul></li></ul><h3 id="两种配置方式对比" tabindex="-1">两种配置方式对比 <a class="header-anchor" href="#两种配置方式对比" aria-label="Permalink to “两种配置方式对比”">​</a></h3><h4 id="方式一-通配符方式" tabindex="-1">方式一：通配符方式 <a class="header-anchor" href="#方式一-通配符方式" aria-label="Permalink to “方式一：通配符方式”">​</a></h4><div class="language-env"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>NTFY_AUTH_ACCESS=*:up*:read-write</span></span></code></pre></div><ul><li>优点：简单，一次配置所有 UnifiedPush 主题</li><li>缺点：任何知道主题名的人都可以发送和接收消息</li></ul><h4 id="方式二-精确主题方式" tabindex="-1">方式二：精确主题方式 <a class="header-anchor" href="#方式二-精确主题方式" aria-label="Permalink to “方式二：精确主题方式”">​</a></h4><div class="language-env"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>NTFY_AUTH_ACCESS=*:up1234567890abc:read-write</span></span></code></pre></div><ul><li>优点：更安全，只有知道精确主题名的应用才能发送</li><li>缺点：需要为每个 UnifiedPush 应用单独配置</li></ul><h2 id="安全建议" tabindex="-1">安全建议 <a class="header-anchor" href="#安全建议" aria-label="Permalink to “安全建议”">​</a></h2><h3 id="_1-使用随机主题名" tabindex="-1">1. 使用随机主题名 <a class="header-anchor" href="#_1-使用随机主题名" aria-label="Permalink to “1. 使用随机主题名”">​</a></h3><p>UnifiedPush 主题名应该是随机的、不可预测的字符串。这相当于一个&quot;密码&quot;，只有知道主题名的人才能发送消息。</p><p>例如：</p><ul><li><code>upabc123def456</code> - 好</li><li><code>upmytopic</code> - 不好（容易被猜到）</li></ul><h3 id="_2-精确主题优于通配符" tabindex="-1">2. 精确主题优于通配符 <a class="header-anchor" href="#_2-精确主题优于通配符" aria-label="Permalink to “2. 精确主题优于通配符”">​</a></h3><p>在生产环境中，建议使用精确主题而非通配符：</p><div class="language-env"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 不推荐</span></span>
<span class="line"><span>NTFY_AUTH_ACCESS=*:up*:read-write</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 推荐</span></span>
<span class="line"><span>NTFY_AUTH_ACCESS=*:upabc123def456:read-write</span></span></code></pre></div><h3 id="_3-限制主题数量" tabindex="-1">3. 限制主题数量 <a class="header-anchor" href="#_3-限制主题数量" aria-label="Permalink to “3. 限制主题数量”">​</a></h3><p>如果使用通配符，可以通过 rate limiting 限制单个主题的消息频率：</p><div class="language-env"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>NTFY_VISITOR_MESSAGE_DAILY_LIMIT=1000</span></span></code></pre></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to “常见问题”">​</a></h2><h3 id="q-设置后仍然无法接收通知" tabindex="-1">Q: 设置后仍然无法接收通知？ <a class="header-anchor" href="#q-设置后仍然无法接收通知" aria-label="Permalink to “Q: 设置后仍然无法接收通知？”">​</a></h3><p>检查 ACL 配置是否正确：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 进入容器查看 ACL</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ntfy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ntfy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> access</span></span></code></pre></div><p>确保 <code>*</code> 用户对 <code>up*</code> 主题有 read-write 权限。</p><h3 id="q-如何查看-unifiedpush-主题" tabindex="-1">Q: 如何查看 UnifiedPush 主题？ <a class="header-anchor" href="#q-如何查看-unifiedpush-主题" aria-label="Permalink to “Q: 如何查看 UnifiedPush 主题？”">​</a></h3><p>在手机上的 ntfy/Android 应用中，订阅 UnifiedPush 后可以在设置中查看主题名。</p><h3 id="q-支持哪些-unifiedpush-应用" tabindex="-1">Q: 支持哪些 UnifiedPush 应用？ <a class="header-anchor" href="#q-支持哪些-unifiedpush-应用" aria-label="Permalink to “Q: 支持哪些 UnifiedPush 应用？”">​</a></h3><p>详见 <a href="https://unifiedpush.org/users/apps/" target="_blank" rel="noreferrer">UnifiedPush 应用列表</a>。</p><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to “参考链接”">​</a></h2><ul><li><a href="https://docs.ntfy.sh/config/#example-unifiedpush" target="_blank" rel="noreferrer">ntfy 官方文档 - UnifiedPush</a></li><li><a href="https://unifiedpush.org" target="_blank" rel="noreferrer">UnifiedPush 官方文档</a></li><li><a href="https://unifiedpush.org/users/distributors/ntfy/" target="_blank" rel="noreferrer">UnifiedPush ntfy 分发商指南</a></li></ul>`,47)])])}const g=a(l,[["render",p]]);export{k as __pageData,g as default};
